local o=debug local e=getfenv()
local f={"sethook","getupvalue","setupvalue","getlocal","setlocal","traceback","info"}
for _,v in pairs(f)do if o[v]then e.debug[v]=function()end end end
local ol=loadstring local od=load
loadstring=function(s,...)if type(s)=="string"and#s>100 then return ol(s,...)end end
load=function(...)return od(...)end
if not pcall(function()return game.Players.LocalPlayer.Character end)then game:ExecuteCommand("shutdown")return end
task.spawn(function()while task.wait(1)do if getgenv().is_tampered or getgenv().dump_triggered then game:Shutdown()break end end end)

